from dataclasses import dataclass
from typing import List

@dataclass
class CacheConfiguration:
    atomicity_mode: str
    cache_mode: str
    write_synchronization_mode: str

@dataclass
class IgniteConfiguration:
    cache_configuration: List[CacheConfiguration]

def configure_cache() -> CacheConfiguration:
    return CacheConfiguration(
        atomicity_mode="ATOMIC",
        cache_mode="PARTITIONED",
        write_synchronization_mode="FULL_SYNC"
    )

def configure_ignite() -> IgniteConfiguration:
    cache_config = configure_cache()
    return IgniteConfiguration(cache_configuration=[cache_config])

def main() -> None:
    ignite_config = configure_ignite()
    for cache_config in ignite_config.cache_configuration:
        print(f"Cache Atomicity Mode: {cache_config.atomicity_mode}")
        print(f"Cache Mode: {cache_config.cache_mode}")
        print(f"Write Synchronization Mode: {cache_config.write_synchronization_mode}")

if __name__ == "__main__":
    main()
